import React, { useState, useEffect } from "react";
import "./index.css";
import { BrowserRouter } from 'react-router-dom';
import backgroundImg from "./background.jpg";
import loginBackgroundImg from "./login-background.jfif";
import createBackgroundImg from "./create-background.jpg";
import aboutBackgroundImg from "./about-background.jpg";
import contactBackgroundImg from "./contact-background.jpg";
import selectBackgroundImg from "./select-background.jpg"; 
import discoveryBackgroundImg from './firstpage.jpg'; // Import the background image
import ListenerImage from './Listener.png';  
import ArtistImage from './Artist.png';  
import userRepository from "./UserRepository";
import AuthService from "./AuthService";

function App() {
  const [currentPage, setCurrentPage] = useState("home");
  const [userData, setUserData] = useState({
    fullName: "",
    email: "",
    password: "",
    accountType: "",
    genre: "",
    influencedArtists: [],
    likedArtists: []
  });

  const navigateTo = (page) => {
    setCurrentPage(page);
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setUserData({
      ...userData,
      [name]: value
    });
  };

  const handleFormSubmit = (e) => {
    e.preventDefault();
    if (currentPage === "createAccount") {
      navigateTo("accountType");
    }
  };

  const handleAccountTypeSubmit = (e) => {
    e.preventDefault();
    // Handle form submission for account type (e.g., save to database)
    if (userData.accountType === "artist" && userData.genre && userData.influencedArtists.length === 3) {
      // Proceed to artist profile setup or homepage
      navigateTo("home");
    } else if (userData.accountType === "listener" && userData.likedArtists.length === 3) {
      // Proceed to listener profile setup or homepage
      navigateTo("home");
    } else {
      alert("Please fill all required fields.");
    }
  };

  const Home = () => (
    <div
      className="home-container"
      style={{ backgroundImage: `url(${backgroundImg})` }}
    >
      <div className="left-section">
        <nav className="navbar">
          <button className="nav-button" onClick={() => navigateTo("home")}>
            Home
          </button>
          <button className="nav-button" onClick={() => navigateTo("about")}>
            About
          </button>
          <button className="nav-button" onClick={() => navigateTo("contact")}>
            Contact
          </button>
          <button className="nav-button" onClick={() => navigateTo("login")}>
            Login
          </button>
        </nav>
        <div className="content">
          <h1 className="title">Welcome to SoundWake</h1>
          <p className="description">
            We bring the underground to you. Discover new upcoming independent artists, create playlists
          </p>
          <p className="description">and share your experience with friends.</p>
        </div>
      </div>
    </div>
  );

  const AccountType = () => {
    const usr = userRepository.getUser();
    if (!usr || !usr.email) {
      return <div>Error: User is not logged in</div>; // Handle error if user is not found
    }
  
    const email = usr.email;
  
    const handleAccountTypeSubmit = async (type) => {
      if(type == "Artist")
        userRepository.setUser({ accountType: 'artist' });
      else
        userRepository.setUser({ accountType: 'listener' });
      const button = document.getElementById(type);
      if (button) button.disabled = true;
  
      try {
        const response = await fetch("http://localhost:5000/add-account-type", {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
          },
          body: JSON.stringify({ email, accountType: type }),
        });
  
        console.log("Status Code:", response.status); // Log status code
        console.log("Response Headers:", response.headers); // Log headers
  
        const rawText = await response.text(); // Get raw response text
        console.log("Raw Response Text:", rawText); // Log the raw response
  
        if (response.ok) {
          try {
            const jsonData = JSON.parse(rawText); // Try parsing the raw text into JSON
            console.log("Parsed Data:", jsonData);
  
            // Handle the success scenario (if jsonData has a success message)
            if (jsonData.message) {
              console.log(`${type} added successfully`, jsonData);
              navigateTo("genre"); // Navigate to the next page on success
            }
          } catch (error) {
            console.error("Error parsing JSON:", error, "Raw Data:", rawText);
            alert(`Error: Could not parse response as JSON. ${error.message}`); // Alert if JSON parsing fails
          }
        } else {
          console.error("Failed to add account type. Response not ok:", response.statusText);
          alert(`Error: Failed to add account type. Status: ${response.statusText}`);
        }
      } catch (error) {
        console.error("Error during fetch:", error);
        alert(`Error: ${error.message}`); // Display error in alert
      } finally {
        if (button) button.disabled = false; // Re-enable the button after the request completes
      }
    };
  
    return (
      <div
        style={{
          display: "flex",
          flexDirection: "column", // Stack the title and buttons vertically
          justifyContent: "center",
          alignItems: "center",
          height: "100vh",
          backgroundImage: `url(${selectBackgroundImg})`,
          backgroundSize: "cover",
          backgroundPosition: "center",
          textAlign: "center", // Center the text above the buttons
        }}
      >
        {/* Title */}
        <h2 style={{ marginBottom: "40px", color: "white", fontSize: "28px" }}>
          Choose an account type (Listener or Artist)
        </h2>
  
        {/* Buttons */}
        <div
          style={{
            display: "flex",
            justifyContent: "space-between",
            width: "60%", // Adjust width to make sure the buttons fit well
            gap: "20px", // Add spacing between the buttons
          }}
        >
          <button
            id="Listener"
            style={{
              width: "300px", // 2x bigger button size
              height: "300px", // 2x bigger button size to make them square
              border: "none",
              background: "transparent",
              cursor: "pointer",
              transition: "transform 0.3s ease",
              display: "flex", // Center the image inside the button
              justifyContent: "center",
              alignItems: "center",
              borderRadius: "10px", // Optional: adds rounded corners to buttons
            }}
            onClick={() => handleAccountTypeSubmit("Listener")}
            onMouseOver={(e) => (e.currentTarget.style.transform = "scale(1.05)")}
            onMouseOut={(e) => (e.currentTarget.style.transform = "scale(1)")}
          >
            <img
              src={ListenerImage}
              alt="Listener"
              style={{
                width: "100%", // Make image fill the button's size
                height: "100%",
                objectFit: "cover", // Force image to cover the button area, making it square
                borderRadius: "10px", // Optional: rounds the image corners to match button
              }}
            />
          </button>
  
          <button
            id="Artist"
            style={{
              width: "300px", // 2x bigger button size
              height: "300px", // 2x bigger button size to make them square
              border: "none",
              background: "transparent",
              cursor: "pointer",
              transition: "transform 0.3s ease",
              display: "flex", // Center the image inside the button
              justifyContent: "center",
              alignItems: "center",
              borderRadius: "10px", // Optional: adds rounded corners to buttons
            }}
            onClick={() => handleAccountTypeSubmit("Artist")}
            onMouseOver={(e) => (e.currentTarget.style.transform = "scale(1.05)")}
            onMouseOut={(e) => (e.currentTarget.style.transform = "scale(1)")}
          >
            <img
              src={ArtistImage}
              alt="Artist"
              style={{
                width: "100%", // Make image fill the button's size
                height: "100%",
                objectFit: "cover", // Force image to cover the button area, making it square
                borderRadius: "10px", // Optional: rounds the image corners to match button
              }}
            />
          </button>
        </div>
      </div>
    );
  };

  const DiscoveryPage = () => {
    const [searchQuery, setSearchQuery] = useState('');
    
    // Handle back to login click
    const handleBackToLogin = () => {
      navigateTo("login"); // Navigate to the login page
    };
  
    // Handle search input change
    const handleSearchChange = (e) => {
      setSearchQuery(e.target.value);
    };
  
    const handleSearchSubmit = async (e) => {
      e.preventDefault();
      try {
        // Store the artist's full_name in the userRepository
        userRepository.setFullName(searchQuery);
  
        // Navigate to the artist page using the navigateTo function
        navigateTo("artist"); // Navigate to the ArtistPage
      } catch (error) {
        console.error('Error during search:', error);
      }
    };
  
    return (
      <div
        className="discovery-container"
        style={{
          backgroundImage: `url(${discoveryBackgroundImg})`, // Set the imported background image
          backgroundSize: 'cover',
          backgroundPosition: 'center', // Center the background image
          height: '100vh', // Full viewport height
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          justifyContent: 'center',
          color: 'white',
          textAlign: 'center',
          position: 'relative',
          boxSizing: 'border-box',
          overflow: 'hidden',
        }}
      >
        {/* Overlay to darken the background slightly */}
        <div
          style={{
            position: 'absolute',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            backgroundColor: 'rgba(0, 0, 0, 0.4)', // Dark overlay
            zIndex: 1,
          }}
        />
    
        {/* Back to Login Button */}
        <button
          className="back-button"
          style={{
            position: 'absolute',
            top: '20px',
            left: '20px',
            padding: '12px 25px',
            backgroundColor: 'rgba(0, 0, 0, 0.7)', // Semi-transparent background
            color: 'white',
            border: 'none',
            borderRadius: '5px',
            fontSize: '1rem',
            cursor: 'pointer',
            zIndex: 3, // Ensure it is above the overlay
            transition: 'all 0.3s ease',
          }}
          onClick={handleBackToLogin}
          onMouseEnter={(e) => (e.target.style.backgroundColor = 'rgba(0, 0, 0, 0.9)')}
          onMouseLeave={(e) => (e.target.style.backgroundColor = 'rgba(0, 0, 0, 0.7)')}
        >
          Back to Login
        </button>
    
        {/* Large Text in the Center */}
        <h1
          style={{
            fontSize: '4rem',
            fontWeight: 'bold',
            zIndex: 2,
            letterSpacing: '2px',
            textTransform: 'uppercase',
            marginBottom: '20px',
          }}
        >
          Discovery Page
        </h1>
    
        {/* Search Bar Below the Text */}
        <div
          style={{
            zIndex: 2,
            display: 'flex',
            justifyContent: 'center',
            width: '100%',
            padding: '0 20px',
          }}
        >
          <input
            type="text"
            value={searchQuery}
            onChange={handleSearchChange}
            placeholder="Search artists, albums, or songs..."
            style={{
              padding: '15px 30px',
              fontSize: '1.2rem',
              width: '80%',
              maxWidth: '600px',
              borderRadius: '30px',
              border: '2px solid #fff',
              outline: 'none',
              textAlign: 'center',
              color: 'white',
              backgroundColor: 'rgba(0, 0, 0, 0.6)', // Slightly transparent background
              transition: 'all 0.3s ease',
            }}
          />
        </div>
    
        {/* Modern Search Button Below the Input */}
        <button
          onClick={handleSearchSubmit}
          style={{
            marginTop: '15px',
            padding: '15px 30px',
            fontSize: '1.2rem',
            backgroundColor: '#007BFF',
            color: 'white',
            border: 'none',
            borderRadius: '30px',
            cursor: 'pointer',
            zIndex: 3, // Ensure the button is above the overlay
            transition: 'all 0.3s ease',
          }}
          onMouseEnter={(e) => (e.target.style.backgroundColor = '#0056b3')}
          onMouseLeave={(e) => (e.target.style.backgroundColor = '#007BFF')}
        >
          Search
        </button>
      </div>
    );
  };
  

  const ArtistPage = () => {
    const [artist, setArtist] = useState(null); // To store artist's data
    const fullName = userRepository.getFullName(); // Retrieve the artist's full name from the repository

    // Fetch artist data on component mount
    useEffect(() => {
      const fetchArtistData = async () => {
        try {
          const response = await fetch(`http://localhost:5000/artist/${fullName}`);
          const data = await response.json();

          if (data.error) {
            console.error(data.error);
            return;
          }

          setArtist(data); // Store the artist data
        } catch (error) {
          console.error('Error fetching artist data:', error);
        }
      };

      if (fullName) {
        fetchArtistData(); // Fetch artist details when fullName is available
      } else {
        console.log('No artist name found');
      }
    }, [fullName]);

    // Handle back to discovery page
    const handleBackToDiscovery = () => {
      navigateTo("discovery"); // Navigate to the DiscoveryPage
    };

    if (!artist) {
      return <div>Loading artist details...</div>;
    }
  
    return (
      <div
        className="artist-container"
        style={{
          backgroundImage: `url(${artist.wallpaper_path || '/default-wallpaper.jpg'})`, // Fallback to default wallpaper if artist wallpaper is not available
          backgroundSize: 'cover',
          backgroundRepeat: 'no-repeat', // Prevent the image from repeating
          backgroundPosition: 'center',
          height: '100vh',
          width: '100vw', // Ensure it spans the entire viewport width
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          justifyContent: 'center',
          color: 'white',
          textAlign: 'center',
          position: 'relative',
          boxSizing: 'border-box',
        }}
      >
        {/* Overlay */}
        <div
          style={{
            position: 'absolute',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            backgroundColor: 'rgba(0, 0, 0, 0.5)', // Dark overlay
            zIndex: 1,
          }}
        />
  
        {/* Back to Discovery Button */}
        <button
          onClick={handleBackToDiscovery}
          style={{
            position: 'absolute',
            top: '20px',
            left: '20px',
            padding: '12px 25px',
            backgroundColor: 'rgba(0, 0, 0, 0.7)',
            color: 'white',
            border: 'none',
            borderRadius: '5px',
            fontSize: '1rem',
            cursor: 'pointer',
            zIndex: 2,
            transition: 'all 0.3s ease',
          }}
        >
          Back to Discovery
        </button>
  
        {/* Artist Info */}
        <div style={{ zIndex: 2, display: 'flex', alignItems: 'center' }}>
          <img
            src={artist.image_path}
            alt="Artist Icon"
            style={{
              width: '150px',
              height: '150px',
              objectFit: 'cover',
              borderRadius: '50%',
              marginRight: '20px',
            }}
          />
          <div>
            <h1>{artist.full_name}</h1>
            <p>{artist.description}</p>
          </div>
        </div>
      </div>
    );
  };

  const Genre = () => {
    const [genres, setGenres] = useState([]);
    const [userType, setUserType] = useState("");
  
    const usr = userRepository.getUser();
  
    useEffect(() => {
      if (usr && usr.accountType) {
        setUserType(usr.accountType);
      }
    }, [usr]);
  
    useEffect(() => {
      const fetchGenres = async () => {
        try {
          const response = await fetch("http://localhost:5000/genres");
          if (response.ok) {
            const data = await response.json();
            setGenres(data);
          } else {
            console.error("Failed to fetch genres.");
          }
        } catch (error) {
          console.error("Error fetching genres:", error);
        }
      };
  
      fetchGenres();
    }, []);
  
    const handleGenreSelect = async (genre) => {
      try {
        if (userType === "artist" && usr && usr.email) {
          const response = await fetch("http://localhost:5000/update-genre", {
            method: "POST",
            headers: {
              "Content-Type": "application/json",
            },
            body: JSON.stringify({
              email: usr.email,
              genreId: genre.genre_id,
            }),
          });
  
          if (response.ok) {
            const data = await response.json();
            console.log("Genre updated successfully:", data);
          } else {
            console.error("Failed to update genre.");
          }
        }
      } catch (error) {
        console.error("Error selecting genre:", error);
      }
    };
  
    const middleIndex = Math.ceil(genres.length / 2);
    const topRow = genres.slice(0, middleIndex);
    const bottomRow = genres.slice(middleIndex);
  
    return (
      <div
        className="genre-container"
        style={{
          backgroundImage: `url(${selectBackgroundImg})`,
          backgroundSize: "cover",
          backgroundPosition: "center",
          padding: "20px",
          display: "flex",
          flexDirection: "column",
          alignItems: "center",
          justifyContent: "center",
          minHeight: "100vh",
        }}
      >
        <h1
          style={{
            color: "white",
            fontSize: "36px",
            fontWeight: "bold",
            marginBottom: "20px",
          }}
        >
          Choose a genre
        </h1>
  
        {[topRow, bottomRow].map((row, rowIndex) => (
          <div
            key={rowIndex}
            style={{
              display: "flex",
              justifyContent: "center",
              gap: "20px",
              marginBottom: rowIndex === 0 ? "40px" : "0",
            }}
          >
            {row.map((genre) => (
              <button
                key={genre.genre_id}
                className="genre-button"
                style={{
                  backgroundImage: `url(${genre.image_path})`,
                  backgroundSize: "cover",
                  backgroundPosition: "center",
                  width: "200px",
                  height: "200px",
                  border: "none",
                  borderRadius: "10px",
                  cursor: "pointer",
                  transition: "transform 0.3s ease",
                }}
                onClick={() => handleGenreSelect(genre)}
                onMouseOver={(e) => (e.currentTarget.style.transform = "scale(1.1)")}
                onMouseOut={(e) => (e.currentTarget.style.transform = "scale(1)")}
              ></button>
            ))}
          </div>
        ))}
      </div>
    );
  };
  

  const Contact = () => {
    const [fullName, setFullName] = useState("");
    const [email, setEmail] = useState("");
    const [message, setMessage] = useState("");
  
    const handleFullNameChange = (event) => {
      setFullName(event.target.value);
    };
  
    const handleEmailChange = (event) => {
      setEmail(event.target.value);
    };
  
    const handleMessageChange = (event) => {
      setMessage(event.target.value);
    };
  
    return (
      <div
        className="contact-container"
        style={{ backgroundImage: `url(${contactBackgroundImg})` }}
      >
        <nav className="navbar-contact">
          <button className="nav-button" onClick={() => navigateTo("home")}>
            Home
          </button>
          <button className="nav-button" onClick={() => navigateTo("about")}>
            About
          </button>
          <button className="nav-button" onClick={() => navigateTo("contact")}>
            Contact
          </button>
          <button className="nav-button" onClick={() => navigateTo("login")}>
            Login
          </button>
        </nav>
  
        <div className="contact-content">
          {/* Left Section */}
          <div className="contact-left">
            <h1>Tell Us About Your Experience</h1>
            <p>
              We'd love to hear your thoughts! Connect with us on social media or
              fill out the contact form to share your feedback.
            </p>
            <div className="social-icons">
              <a href="https://facebook.com" target="_blank" rel="noopener noreferrer">
                <img src="/facebook.png" alt="Facebook" />
              </a>
              <a href="https://instagram.com" target="_blank" rel="noopener noreferrer">
                <img src="/instagram.png" alt="Instagram" />
              </a>
            </div>
          </div>
  
          {/* Right Section */}
          <div className="contact-form-container">
            <h2>Contact Form</h2>
            <form>
              <input
                type="text"
                placeholder="Full Name"
                value={fullName}
                onChange={handleFullNameChange}
                required
              />
              <input
                type="email"
                placeholder="Email"
                value={email}
                onChange={handleEmailChange}
                required
              />
              <textarea
                placeholder="Message"
                value={message}
                onChange={handleMessageChange}
                required
              ></textarea>
              <button type="submit">Submit</button>
            </form>
          </div>
        </div>
      </div>
    );
  };

  const About = () => (
    <div
      className="about-container"
      style={{ backgroundImage: `url(${aboutBackgroundImg})` }}
    >
      <nav className="navbar-about">
        <button className="nav-about-button" onClick={() => navigateTo("home")}>
          Home
        </button>
        <button className="nav-about-button" onClick={() => navigateTo("about")}>
          About
        </button>
        <button className="nav-about-button" onClick={() => navigateTo("contact")}>
          Contact
        </button>
        <button className="nav-about-button" onClick={() => navigateTo("login")}>
          Login
        </button>
      </nav>
      <div className="about-text">
        <h1>About SoundWake</h1>
        <p>
          SoundWake is your ultimate destination for discovering new music and
          creating personalized playlists. Whether you're exploring new genres or
          revisiting old favorites, SoundWake helps you connect with music in a
          whole new way.
        </p>
        <p>
          Share your playlists with friends, discover curated collections, and
          let SoundWake be the soundtrack to your life. Join a community of
          music lovers and start your journey with us today.
        </p>
      </div>
    </div>
  );

  const Login = () => {
    const [email, setEmail] = useState("");
    const [password, setPassword] = useState("");
    const [error, setError] = useState(""); // To handle error messages
  
    const handleEmailChange = (event) => {
      setEmail(event.target.value);
    };
  
    const handlePasswordChange = (event) => {
      setPassword(event.target.value);
    };
  
    const handleLoginSubmit = async (e) => {
      e.preventDefault();
      try {
        const response = await AuthService.login(email, password);
        // Handle successful login (e.g., redirect, set user context)
        console.log("Logged in user:", response.user);
        navigateTo("discovery");
      } catch (error) {
        console.error("Login error:", error);
        // Handle error (e.g., show error message)
      }
    };
    
  
    return (
      <div
        className="login-container"
        style={{ backgroundImage: `url(${loginBackgroundImg})`, backgroundSize: "cover", backgroundPosition: "center" }}
      >
        <div className="login-form-container">
          <h1>Login</h1>
          <form onSubmit={handleLoginSubmit}>
            <input
              type="email"
              placeholder="Email"
              value={email}
              onChange={handleEmailChange}
              required
            />
            <input
              type="password"
              placeholder="Password"
              value={password}
              onChange={handlePasswordChange}
              required
            />
            <button type="submit">Login</button>
          </form>
          {error && <p className="error-message">{error}</p>} {/* Display error message if login fails */}
          <button onClick={() => navigateTo("home")} className="back-button">
            Back to Home
          </button>
          <p className="create-account-option">
            Don't have an account yet?{" "}
            <span
              className="create-account-link"
              onClick={() => navigateTo("createAccount")}
            >
              Create one
            </span>
          </p>
        </div>
      </div>
    );
  };



  const CreateAccount = () => {
    const [fullName, setFullName] = useState("");
    const [email, setEmail] = useState("");
    const [password, setPassword] = useState("");

    const handleFullNameChange = (event) => setFullName(event.target.value);
    const handleEmailChange = (event) => setEmail(event.target.value);
    const handlePasswordChange = (event) => setPassword(event.target.value);

    const handleSubmit = (event) => {
      event.preventDefault();

      // Create the user by sending a request to the backend
      fetch("http://localhost:5000/create-account", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({ fullName, email, password }),
      })
        .then((response) => {
          if (!response.ok) {
            throw new Error("Failed to create account");
          }
          return response.json(); // Parse the JSON response
        })
        .then((data) => {
          // On success, store the user data in the UserRepository
          userRepository.setUser({ fullName, email, password }); // Store the user data
          console.log("User created successfully:", data);

          // Navigate to the AccountType page
          navigateTo("accountType");
        })
        .catch((error) => {
          console.error("Error creating user:", error);
        });
    };
    return (
      <div className="create-container" style={{ backgroundImage: `url(${createBackgroundImg})` }}>
        <div className="create-form-container">
          <h1>Create Account</h1>
          <form onSubmit={handleSubmit}>
            <input
              type="text"
              placeholder="Full Name"
              value={fullName}
              onChange={handleFullNameChange}
              required
            />
            <input
              type="email"
              placeholder="Email"
              value={email}
              onChange={handleEmailChange}
              required
            />
            <input
              type="password"
              placeholder="Password"
              value={password}
              onChange={handlePasswordChange}
              required
            />
            <button type="submit">Sign Up</button>
          </form>
          <button onClick={() => navigateTo("login")} className="back-button">
            Back to Login
          </button>
        </div>
      </div>
    );
  };
  
  

  return (
    <BrowserRouter>
      <div>
        {currentPage === "home" && <Home />}
        {currentPage === "login" && <Login />}
        {currentPage === "about" && <About />}
        {currentPage === "contact" && <Contact />}
        {currentPage === "createAccount" && <CreateAccount />}
        {currentPage === "accountType" && <AccountType />}
        {currentPage === "genre" && <Genre />}
        {currentPage === "discovery" && <DiscoveryPage />}
        {currentPage === "artist" && <ArtistPage />}
      </div>
    </BrowserRouter>
  );
}

export default App;
